#!/bin/bash
set -euo pipefail

SCRIPT_DIR="$(cd "$(dirname "$0")" && pwd)"

# The all-in-one configuration serves the same 30-server corpus as the tiered
# configuration; only the route layout differs (one shared route vs. /light,
# /medium, /heavy). install-tiered.sh is generated by
# mcp-benchmark/scripts/sync_ec2_repos.py and is the standalone full-corpus
# installer, so reuse it directly to keep pinned commits, npm packages, and
# build steps identical across both configurations.
bash "${SCRIPT_DIR}/install-tiered.sh"

echo "INFO: all-in-one server install complete"
